// Generated by forge proof from fs-watch-sessions-list.md, fs-watch-specs-tab.md, fs-watch-pipeline-tab.md, fs-watch-session-events.md, fs-watch-rerender-profile.md
import { describe, test, expect, beforeEach, afterEach } from 'bun:test';
import { createFileWatcher, type FileWatcherHandle } from './file-watcher.js';
import { writeFile, mkdir, rm, readFile } from 'fs/promises';
import { join } from 'path';
import { tmpdir } from 'os';
import { randomUUID } from 'crypto';

// ── Helpers ──────────────────────────────────────────────────

function sleep(ms: number): Promise<void> {
  return new Promise(resolve => setTimeout(resolve, ms));
}

let testDir: string;
let handles: FileWatcherHandle[];

beforeEach(async () => {
  testDir = join(tmpdir(), `forge-fw-tui-test-${randomUUID()}`);
  await mkdir(testDir, { recursive: true });
  handles = [];
});

afterEach(async () => {
  for (const h of handles) h.dispose();
  handles = [];
  await rm(testDir, { recursive: true, force: true }).catch(() => {});
});

function track(handle: FileWatcherHandle): FileWatcherHandle {
  handles.push(handle);
  return handle;
}

// ── Sessions list: directory watching ───────────────────────

describe('fs-watch sessions list: directory watches', () => {
  test('watches .forge/sessions/ directory for new sessions', async () => {
    const sessionsDir = join(testDir, '.forge', 'sessions');
    await mkdir(sessionsDir, { recursive: true });

    let callCount = 0;
    const handle = track(createFileWatcher(sessionsDir, () => { callCount++; }, {
      debounceMs: 50,
      fallbackIntervalMs: 100,
      type: 'directory',
    }));

    // Create a new session directory
    await mkdir(join(sessionsDir, 'new-session'));
    await sleep(300);

    expect(callCount).toBeGreaterThanOrEqual(1);
  });

  test('watches .forge/results/ directory for completed sessions', async () => {
    const resultsDir = join(testDir, '.forge', 'results');
    await mkdir(resultsDir, { recursive: true });

    let callCount = 0;
    const handle = track(createFileWatcher(resultsDir, () => { callCount++; }, {
      debounceMs: 50,
      fallbackIntervalMs: 100,
      type: 'directory',
    }));

    // Create a result directory
    const resultDir = join(resultsDir, '2026-03-11T00:00:00Z');
    await mkdir(resultDir, { recursive: true });
    await writeFile(join(resultDir, 'summary.json'), '{}');
    await sleep(300);

    expect(callCount).toBeGreaterThanOrEqual(1);
  });

  test('watches .forge/latest-session.json for session start', async () => {
    const forgeDir = join(testDir, '.forge');
    await mkdir(forgeDir, { recursive: true });
    const latestPath = join(forgeDir, 'latest-session.json');
    await writeFile(latestPath, JSON.stringify({ sessionId: 'old' }));

    let callCount = 0;
    const handle = track(createFileWatcher(latestPath, () => { callCount++; }, {
      debounceMs: 50,
      fallbackIntervalMs: 100,
    }));

    // Update latest-session.json
    await writeFile(latestPath, JSON.stringify({ sessionId: 'new-session' }));
    await sleep(300);

    expect(callCount).toBeGreaterThanOrEqual(1);
  });

  test('handles missing .forge/sessions/ directory gracefully', () => {
    const missingPath = join(testDir, '.forge', 'sessions');
    // Should not throw when directory doesn't exist
    let callCount = 0;
    const handle = track(createFileWatcher(missingPath, () => { callCount++; }, {
      debounceMs: 50,
      fallbackIntervalMs: 200,
      type: 'directory',
    }));

    // Falls back to polling without crash
    expect(handle).toBeDefined();
  });

  test('all watchers disposed on cleanup', async () => {
    const sessionsDir = join(testDir, '.forge', 'sessions');
    const resultsDir = join(testDir, '.forge', 'results');
    const latestPath = join(testDir, '.forge', 'latest-session.json');
    await mkdir(sessionsDir, { recursive: true });
    await mkdir(resultsDir, { recursive: true });
    await writeFile(latestPath, '{}');

    const h1 = track(createFileWatcher(sessionsDir, () => {}, { type: 'directory', debounceMs: 50, fallbackIntervalMs: 60000 }));
    const h2 = track(createFileWatcher(resultsDir, () => {}, { type: 'directory', debounceMs: 50, fallbackIntervalMs: 60000 }));
    const h3 = track(createFileWatcher(latestPath, () => {}, { debounceMs: 50, fallbackIntervalMs: 60000 }));

    // Dispose all
    h1.dispose();
    h2.dispose();
    h3.dispose();

    // Should not throw or produce errors
    await sleep(100);
  });
});

// ── Sessions list: debounced callback ───────────────────────

describe('fs-watch sessions list: debounced reload', () => {
  test('single debounced callback handles all three watch sources', async () => {
    let reloadCount = 0;
    const reload = () => { reloadCount++; };

    const forgeDir = join(testDir, '.forge');
    await mkdir(join(forgeDir, 'sessions'), { recursive: true });
    await mkdir(join(forgeDir, 'results'), { recursive: true });
    await writeFile(join(forgeDir, 'latest-session.json'), '{}');

    // All three watchers call the same reload function
    const h1 = track(createFileWatcher(join(forgeDir, 'sessions'), reload, { type: 'directory', debounceMs: 100, fallbackIntervalMs: 60000 }));
    const h2 = track(createFileWatcher(join(forgeDir, 'results'), reload, { type: 'directory', debounceMs: 100, fallbackIntervalMs: 60000 }));
    const h3 = track(createFileWatcher(join(forgeDir, 'latest-session.json'), reload, { debounceMs: 100, fallbackIntervalMs: 60000 }));

    // Trigger changes on multiple sources rapidly
    await mkdir(join(forgeDir, 'sessions', 'new-sess'));
    await writeFile(join(forgeDir, 'latest-session.json'), JSON.stringify({ sessionId: 'new-sess' }));
    await sleep(300);

    // Reload called at least once from the changes
    expect(reloadCount).toBeGreaterThanOrEqual(1);
  });

  test('initial load happens immediately on mount (not deferred)', async () => {
    // Simulate initial load pattern: load first, then set up watchers
    let loaded = false;
    const load = () => { loaded = true; };

    // Initial load (synchronous-style)
    load();
    expect(loaded).toBe(true);

    // Then set up watcher for subsequent changes
    const forgeDir = join(testDir, '.forge');
    await mkdir(forgeDir, { recursive: true });
    await writeFile(join(forgeDir, 'latest-session.json'), '{}');
    const handle = track(createFileWatcher(join(forgeDir, 'latest-session.json'), load, { debounceMs: 50, fallbackIntervalMs: 60000 }));
  });
});

// ── Specs tab: manifest file watching ───────────────────────

describe('fs-watch specs tab: manifest watching', () => {
  test('watches .forge/specs.json for manifest changes', async () => {
    const forgeDir = join(testDir, '.forge');
    await mkdir(forgeDir, { recursive: true });
    const specsPath = join(forgeDir, 'specs.json');
    await writeFile(specsPath, JSON.stringify({ version: 1, specs: [] }));

    let callCount = 0;
    const handle = track(createFileWatcher(specsPath, () => { callCount++; }, {
      debounceMs: 50,
      fallbackIntervalMs: 100,
    }));

    // Simulate manifest update (atomic write: tmp + rename)
    const tmpPath = specsPath + '.tmp';
    await writeFile(tmpPath, JSON.stringify({ version: 1, specs: [{ spec: 'new.md' }] }));
    const { rename } = await import('fs/promises');
    await rename(tmpPath, specsPath);

    await sleep(300);
    expect(callCount).toBeGreaterThanOrEqual(1);
  });

  test('no duplicate loadManifest calls from overlapping debounce and fallback', async () => {
    const forgeDir = join(testDir, '.forge');
    await mkdir(forgeDir, { recursive: true });
    const specsPath = join(forgeDir, 'specs.json');
    await writeFile(specsPath, '{}');

    let callCount = 0;
    const handle = track(createFileWatcher(specsPath, () => { callCount++; }, {
      debounceMs: 200,
      fallbackIntervalMs: 200,
    }));

    // Wait for at most one debounce + one fallback cycle
    await sleep(500);

    // Should be a reasonable number (not excessive duplicates)
    // Fallback fires every 200ms, so expect ~2-3 in 500ms
    expect(callCount).toBeLessThanOrEqual(5);
  });

  test('watcher disposed on unmount', async () => {
    const forgeDir = join(testDir, '.forge');
    await mkdir(forgeDir, { recursive: true });
    const specsPath = join(forgeDir, 'specs.json');
    await writeFile(specsPath, '{}');

    let callCount = 0;
    const handle = createFileWatcher(specsPath, () => { callCount++; }, {
      debounceMs: 50,
      fallbackIntervalMs: 100,
    });

    handle.dispose();
    const countAtDispose = callCount;

    await sleep(300);
    expect(callCount).toBe(countAtDispose);
  });
});

