// ── Session events: events.jsonl watching ───────────────────

describe('fs-watch session events: events.jsonl watching', () => {
  test('watches specific events.jsonl file for selected session', async () => {
    const sessionDir = join(testDir, '.forge', 'sessions', 'sess-1');
    await mkdir(sessionDir, { recursive: true });
    const eventsPath = join(sessionDir, 'events.jsonl');
    await writeFile(eventsPath, '{"type":"session_start"}\n');

    let callCount = 0;
    const handle = track(createFileWatcher(eventsPath, () => { callCount++; }, {
      debounceMs: 50,
      fallbackIntervalMs: 100,
    }));

    // Append new event
    const { appendFile } = await import('fs/promises');
    await appendFile(eventsPath, '{"type":"text_delta","content":"hello"}\n');
    await sleep(300);

    expect(callCount).toBeGreaterThanOrEqual(1);
  });

  test('previous session watcher disposed before creating new one', async () => {
    const session1Dir = join(testDir, '.forge', 'sessions', 'sess-1');
    const session2Dir = join(testDir, '.forge', 'sessions', 'sess-2');
    await mkdir(session1Dir, { recursive: true });
    await mkdir(session2Dir, { recursive: true });
    const events1 = join(session1Dir, 'events.jsonl');
    const events2 = join(session2Dir, 'events.jsonl');
    await writeFile(events1, '{"type":"session_start"}\n');
    await writeFile(events2, '{"type":"session_start"}\n');

    let call1Count = 0;
    let call2Count = 0;

    // Watch session 1
    const handle1 = createFileWatcher(events1, () => { call1Count++; }, {
      debounceMs: 50,
      fallbackIntervalMs: 100,
    });

    // Dispose session 1 before watching session 2
    handle1.dispose();
    const countAfterDispose = call1Count;

    // Watch session 2
    const handle2 = track(createFileWatcher(events2, () => { call2Count++; }, {
      debounceMs: 50,
      fallbackIntervalMs: 100,
    }));

    await sleep(300);

    // Session 1 watcher should not fire after dispose
    expect(call1Count).toBe(countAfterDispose);
    // Session 2 watcher should be active
    expect(call2Count).toBeGreaterThanOrEqual(1);
  });

  test('adaptive fallback: short interval while running, long when idle', () => {
    // Adaptive fallback intervals
    const runningInterval = 3000; // 2-5s while session is running
    const idleInterval = 15000;   // 15-30s when completed

    expect(runningInterval).toBeLessThanOrEqual(5000);
    expect(idleInterval).toBeGreaterThanOrEqual(15000);
  });

  test('handles legacy stream.log fallback path', async () => {
    const sessionDir = join(testDir, '.forge', 'sessions', 'legacy-sess');
    await mkdir(sessionDir, { recursive: true });
    // Only stream.log, no events.jsonl
    const logPath = join(sessionDir, 'stream.log');
    await writeFile(logPath, '[ts] Session started\n');

    let callCount = 0;
    const handle = track(createFileWatcher(logPath, () => { callCount++; }, {
      debounceMs: 50,
      fallbackIntervalMs: 100,
    }));

    // Append to stream.log
    const { appendFile } = await import('fs/promises');
    await appendFile(logPath, '[ts] Reading file...\n');
    await sleep(300);

    expect(callCount).toBeGreaterThanOrEqual(1);
  });
});

// ── Incremental byte-offset pattern preservation ────────────

describe('fs-watch session events: incremental reader', () => {
  test('byte offset tracks position for incremental reads', async () => {
    const sessionDir = join(testDir, '.forge', 'sessions', 'incr-sess');
    await mkdir(sessionDir, { recursive: true });
    const eventsPath = join(sessionDir, 'events.jsonl');

    // Write initial events
    const event1 = JSON.stringify({ type: 'session_start', timestamp: '2026-01-01T00:00:00Z' });
    const event2 = JSON.stringify({ type: 'text_delta', timestamp: '2026-01-01T00:00:01Z', content: 'hello' });
    await writeFile(eventsPath, event1 + '\n' + event2 + '\n');

    // Read full content and track offset
    const content = await readFile(eventsPath, 'utf-8');
    let offset = Buffer.byteLength(content, 'utf-8');

    // Append more events
    const event3 = JSON.stringify({ type: 'session_end', timestamp: '2026-01-01T00:01:00Z', durationSeconds: 60, status: 'success' });
    const { appendFile } = await import('fs/promises');
    await appendFile(eventsPath, event3 + '\n');

    // Read only new content from offset
    const fullContent = await readFile(eventsPath, 'utf-8');
    const newContent = fullContent.slice(offset);
    const newEvents = newContent.split('\n').filter(l => l.trim()).map(l => JSON.parse(l));

    expect(newEvents).toHaveLength(1);
    expect(newEvents[0].type).toBe('session_end');
  });
});

// ── Re-render profiling ─────────────────────────────────────

describe('fs-watch rerender profile: benchmark validation', () => {
  test('manifest parse time for typical 36k specs.json', async () => {
    const forgeDir = join(testDir, '.forge');
    await mkdir(forgeDir, { recursive: true });

    // Create a ~36k manifest
    const specs = Array.from({ length: 50 }, (_, i) => ({
      spec: `specs/feature-${i}.md`,
      status: i % 3 === 0 ? 'passed' : i % 3 === 1 ? 'failed' : 'pending',
      runs: Array.from({ length: 3 }, (_, j) => ({
        runId: `run-${i}-${j}`,
        timestamp: `2026-0${(j + 1)}-01T00:00:00Z`,
        resultPath: `.forge/results/run-${i}-${j}`,
        status: j === 2 ? 'passed' : 'failed',
        costUsd: 0.5 + Math.random(),
        durationSeconds: 30 + Math.random() * 90,
      })),
      source: 'file',
      createdAt: '2026-01-01T00:00:00Z',
      updatedAt: '2026-03-01T00:00:00Z',
    }));
    const manifest = JSON.stringify({ version: 1, specs });

    const manifestPath = join(forgeDir, 'specs.json');
    await writeFile(manifestPath, manifest);

    // Measure parse time
    const start = performance.now();
    const raw = await readFile(manifestPath, 'utf-8');
    JSON.parse(raw);
    const elapsed = performance.now() - start;

    // Parse should be well under 16ms for 36k JSON
    expect(elapsed).toBeLessThan(100); // generous bound; typically <5ms
  });

  test('session scan time for moderate session count', async () => {
    const sessionsDir = join(testDir, '.forge', 'sessions');
    const resultsDir = join(testDir, '.forge', 'results');
    await mkdir(sessionsDir, { recursive: true });
    await mkdir(resultsDir, { recursive: true });

    // Create 20 sessions
    for (let i = 0; i < 20; i++) {
      const sid = `sess-${String(i).padStart(3, '0')}`;
      await mkdir(join(sessionsDir, sid), { recursive: true });
      await writeFile(join(sessionsDir, sid, 'events.jsonl'), '{}');
    }
    // Create 20 results
    for (let i = 0; i < 20; i++) {
      const ts = `2026-01-${String(i + 1).padStart(2, '0')}T00:00:00Z`;
      await mkdir(join(resultsDir, ts), { recursive: true });
      await writeFile(join(resultsDir, ts, 'summary.json'), JSON.stringify({ status: 'success' }));
    }

    // Measure scan time
    const start = performance.now();
    const [sessionDirs, resultDirs] = await Promise.all([
      import('fs/promises').then(f => f.readdir(sessionsDir)),
      import('fs/promises').then(f => f.readdir(resultsDir)),
    ]);
    const elapsed = performance.now() - start;

    expect(sessionDirs).toHaveLength(20);
    expect(resultDirs).toHaveLength(20);
    // Directory scan should be fast
    expect(elapsed).toBeLessThan(500); // generous bound
  });

  test('debounce interval validation: 50-100ms debounce keeps UI responsive', () => {
    // The chosen debounce interval should be >= 50ms (avoid excessive redraws)
    // and <= 100ms (keep updates feeling responsive)
    const debounceMs = 100; // default from file-watcher.ts
    expect(debounceMs).toBeGreaterThanOrEqual(50);
    expect(debounceMs).toBeLessThanOrEqual(200);
  });

  test('fallback polling interval: 10-30s as safety net', () => {
    const fallbackMs = 15000; // default from file-watcher.ts
    expect(fallbackMs).toBeGreaterThanOrEqual(10000);
    expect(fallbackMs).toBeLessThanOrEqual(30000);
  });
});
